code = """import pandas as pd
import json
import re

# Load data
sales_path = locals()['var_function-call-11167553081244031459']
tracks_path = locals()['var_function-call-13338430571201753838']

with open(sales_path, 'r') as f:
    sales_data = json.load(f)
df_sales = pd.DataFrame(sales_data)
df_sales['revenue_usd'] = pd.to_numeric(df_sales['total_revenue'])

with open(tracks_path, 'r') as f:
    tracks_data = json.load(f)
df_tracks = pd.DataFrame(tracks_data)

df_merged = pd.merge(df_sales, df_tracks, on='track_id', how='inner')

def clean_field(s):
    if s is None: return ""
    s = str(s).strip()
    if s.lower() in ['none', '[unknown]', 'unk.', '']:
        return ""
    return s

def get_artist(row):
    # Just extract artist
    raw_title = clean_field(row['title'])
    raw_artist = clean_field(row['artist'])
    title = re.sub(r'^\d+-\s*', '', raw_title)
    artist = raw_artist
    if artist == "" and " - " in title:
        parts = title.split(" - ", 1)
        artist = parts[0].strip()
        
    return artist.lower()

df_merged['clean_artist'] = df_merged.apply(get_artist, axis=1)

# Group by artist
artist_rev = df_merged.groupby('clean_artist')['revenue_usd'].sum().reset_index()
top_artists = artist_rev.sort_values('revenue_usd', ascending=False).head(15)

print("__RESULT__:")
print(top_artists.to_json(orient='records'))"""

